      -- Velocity Injector Script | Fullscreen GUI with "ПРИВЕТ"
-- При нажатии на любую кнопку интерфейс исчезает

-- Создаем ScreenGui (полноэкранный)
local screenGui = Instance.new("ScreenGui")
screenGui.Name = "VelocityInjector"
screenGui.ResetOnSpawn = false
screenGui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling

-- Делаем его полноэкранным и поверх всего
screenGui.Parent = game.CoreGui or game.Players.LocalPlayer:WaitForChild("PlayerGui")

-- Затемняющий фон (полупрозрачный черный, для стиля)
local background = Instance.new("Frame")
background.Size = UDim2.new(1, 0, 1, 0)
background.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
background.BackgroundTransparency = 0.3
background.BorderSizePixel = 0
background.Parent = screenGui

-- Центральная панель с текстом и кнопками
local mainFrame = Instance.new("Frame")
mainFrame.Size = UDim2.new(0, 400, 0, 300)
mainFrame.Position = UDim2.new(0.5, -200, 0.5, -150)
mainFrame.BackgroundColor3 = Color3.fromRGB(25, 25, 35)
mainFrame.BackgroundTransparency = 0.15
mainFrame.BorderSizePixel = 0
mainFrame.ClipsDescendants = true
mainFrame.Parent = screenGui

-- Скругление углов (опционально)
local corner = Instance.new("UICorner")
corner.CornerRadius = UDim.new(0, 20)
corner.Parent = mainFrame

-- Текст "ПРИВЕТ"
local textLabel = Instance.new("TextLabel")
textLabel.Size = UDim2.new(1, 0, 0, 100)
textLabel.Position = UDim2.new(0, 0, 0, 30)
textLabel.BackgroundTransparency = 1
textLabel.Text = "ПРЯНЕГ ВЫ НУБ?"
textLabel.TextColor3 = Color3.fromRGB(255, 255, 255)
textLabel.TextSize = 48
textLabel.TextScaled = false
textLabel.Font = Enum.Font.GothamBlack
textLabel.TextStrokeTransparency = 0.5
textLabel.TextStrokeColor3 = Color3.fromRGB(0, 0, 0)
textLabel.Parent = mainFrame

-- Контейнер для кнопок (горизонтальный ряд)
local buttonContainer = Instance.new("Frame")
buttonContainer.Size = UDim2.new(1, 0, 0, 60)
buttonContainer.Position = UDim2.new(0, 0, 1, -80)
buttonContainer.BackgroundTransparency = 1
buttonContainer.Parent = mainFrame

-- Кнопка "ПРИВЕТ"
local helloButton = Instance.new("TextButton")
helloButton.Size = UDim2.new(0, 150, 1, 0)
helloButton.Position = UDim2.new(0.5, -160, 0, 0)
helloButton.BackgroundColor3 = Color3.fromRGB(70, 130, 200)
helloButton.Text = "НЕТ СОСИ"
helloButton.TextColor3 = Color3.fromRGB(255, 255, 255)
helloButton.TextSize = 24
helloButton.Font = Enum.Font.GothamBold
helloButton.BorderSizePixel = 0
helloButton.Parent = buttonContainer

-- Скругление для кнопки
local btnCorner1 = Instance.new("UICorner")
btnCorner1.CornerRadius = UDim.new(0, 12)
btnCorner1.Parent = helloButton

-- Кнопка "ПОКА"
local byeButton = Instance.new("TextButton")
byeButton.Size = UDim2.new(0, 150, 1, 0)
byeButton.Position = UDim2.new(0.5, 10, 0, 0)
byeButton.BackgroundColor3 = Color3.fromRGB(200, 70, 70)
byeButton.Text = "(ОБЛИЗНУТЬ ПЯТКУ)"
byeButton.TextColor3 = Color3.fromRGB(255, 255, 255)
byeButton.TextSize = 24
byeButton.Font = Enum.Font.GothamBold
byeButton.BorderSizePixel = 0
byeButton.Parent = buttonContainer

local btnCorner2 = Instance.new("UICorner")
btnCorner2.CornerRadius = UDim.new(0, 12)
btnCorner2.Parent = byeButton

-- Эффект наведения для кнопок
local function setupButton(button, defaultColor, hoverColor)
    button.MouseEnter:Connect(function()
        button.BackgroundColor3 = hoverColor
    end)
    button.MouseLeave:Connect(function()
        button.BackgroundColor3 = defaultColor
    end)
end

setupButton(helloButton, Color3.fromRGB(70, 130, 200), Color3.fromRGB(100, 160, 230))
setupButton(byeButton, Color3.fromRGB(200, 70, 70), Color3.fromRGB(230, 100, 100))

-- Функция закрытия (удаляет весь GUI)
local function closeUI()
    if screenGui and screenGui.Parent then
        screenGui:Destroy()
    end
end

-- При нажатии на любую кнопку — закрываем интерфейс
helloButton.MouseButton1Click:Connect(closeUI)
byeButton.MouseButton1Click:Connect(closeUI)

-- Дополнительно: если нажать на фон (необязательно, но для удобства)
background.InputBegan:Connect(function(input)
    if input.UserInputType == Enum.UserInputType.MouseButton1 then
        closeUI()
    end
end)

print("Velocity Injector: GUI загружен. Нажми любую кнопку для закрытия.")
